(function(w){"use strict";const ID="bmr";function compute(x){const sex=x.sex,age=Number(x.age),h=Number(x.height),weight=Number(x.weight);if(!["male","female"].includes(sex)||![age,h,weight].every(Number.isFinite)||age<=0||h<=0||weight<=0)return{error:"성별·나이·키·몸무게를 올바르게 입력해 주세요."};const bmr=10*weight+6.25*h-5*age+(sex==="male"?5:-161);return{bmr}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>성별</label><select class="hm-calc-select"><option value="male">남성</option><option value="female">여성</option></select></div><div class="hm-calc-field"><label>나이</label><input class="hm-calc-input" inputmode="numeric"></div><div class="hm-calc-field"><label>키 (cm)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>몸무게 (kg)</label><input class="hm-calc-input" inputmode="decimal"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">BMR 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div><p class="hm-calc-note">미플린-세인트조르(Mifflin-St Jeor) 공식을 이용한 추정치입니다.</p></div>`;const sex=root.querySelector("select"),ins=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({sex:sex.value,age:api.parseNumber(ins[0].value),height:api.parseNumber(ins[1].value),weight:api.parseNumber(ins[2].value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("예상 기초대사량",`${api.formatNumber(r.bmr,0)} kcal/일`));});}w.HM_CALC.register(ID,{compute,render});})(window);
